#!/usr/bin/env python3
from __future__ import annotations
import json, re
from pathlib import Path
from pypinyin import lazy_pinyin, Style

ROOT = Path(__file__).resolve().parents[1]
READING = ROOT / 'data' / 'reading'


def pinyin(text: str) -> str:
    parts = lazy_pinyin(text, style=Style.TONE, neutral_tone_with_five=False, errors=lambda x: list(x))
    out = ' '.join(parts)
    out = re.sub(r'\s+([，。！？；：、“”‘’（）《》])', r'\1', out)
    out = re.sub(r'([“‘（《])\s+', r'\1', out)
    return out[:1].upper() + out[1:] if out else ''


def han_count(text: str) -> int:
    return len(re.findall(r'[\u3400-\u9fff]', text))


def make(level: int, slug: str, title: str, topic: str, target: int, pairs: list[tuple[str,str]]) -> dict:
    total = han_count(''.join(x[0] for x in pairs))
    return {
        'id': f'READ-L{level}-{slug}',
        'level': str(level),
        'title': title,
        'topic': topic,
        'targetCharacters': target,
        'actualCharacters': total,
        'sentences': [
            {'id': f'READ-L{level}-{slug}-S{i+1:02d}', 'zh': zh, 'pinyin': pinyin(zh), 'vi': vi}
            for i, (zh, vi) in enumerate(pairs)
        ]
    }

