def enrich(items):
    out=[]
    for slug,title,topic,pairs,target in items:
        out.append((slug,title,topic,pairs + EXTENSIONS.get(slug, []),target))
    return out


def write(level: int, display: str, target: int, items):
    passages = [make(level, slug, title, topic, target, pairs) for slug,title,topic,pairs,_ in items]
    payload = {
        'meta': {
            'level': str(level), 'displayLevel': display, 'version': '7.0.0',
            'targetCharacters': target, 'passageCount': len(passages),
            'description': 'Bài đọc biên soạn theo độ dài mục tiêu, có pinyin, highlight từ và dịch từng câu.'
        },
        'passages': passages
    }
    (READING / f'hsk{level}.json').write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding='utf-8')
    return passages

if __name__ == '__main__':
    p6 = write(6, '6', 1000, enrich(HSK6))
    p7 = write(7, '7–9', 1500, enrich(HSK7))
    meta_path = READING / 'meta.json'
    meta = json.loads(meta_path.read_text(encoding='utf-8'))
    meta['version'] = '7.0.0'
    meta['levels']['6'] = {'passages': len(p6), 'lengths': [p['actualCharacters'] for p in p6]}
    meta['levels']['7'] = {'passages': len(p7), 'lengths': [p['actualCharacters'] for p in p7]}
    meta_path.write_text(json.dumps(meta, ensure_ascii=False, indent=2), encoding='utf-8')
    print('HSK6:', [p['actualCharacters'] for p in p6])
    print('HSK7:', [p['actualCharacters'] for p in p7])
